import React, {useMemo} from "react";
import {useLanguage} from "../../hooks";

import type {ILinkComponent} from "@lmb-it/kitsconcerto-types";
import {ResponsiveElement, useSeparator} from "../../factory";

const Link: React.FC<ILinkComponent> = ({
  variant,
  isExternal,
  as,
  children,
  to,
  href,
  ...props
}) => {
  const componentType = to ? "Router" : "a";

  const { t } = useLanguage();
  const classes = useMemo(() => {
    const classes: string[] = [];
    if (!variant) {
      classes.push(`kits-text-${as}`);
    } else {
      classes.push(`kits-text-${variant}`);
    }

    return classes.join(" ");
  }, [as, variant]);

  const { cssProps, nativeProps } = useSeparator<any>(props);

  const componentProps = to
    ? { to }
    : {
        href,
        target: isExternal ? "_blank" : undefined,
        rel: isExternal ? "noopener noreferrer" : undefined,
      };

  return (
    <ResponsiveElement
      as={componentType}
      additionalClasses={classes}
      additionalStyles={{
        display: "flex",
        fontFamily: "var(--font-family)",
      }}
      cssProps={cssProps}
      nativeProps={
        nativeProps ? { ...componentProps, ...nativeProps } : componentProps
      }
    >
      {children}
    </ResponsiveElement>
  );
};

export default Link;
